 11→// This is a deterrent, NOT a security boundary — npm packages are public and this key
 12→// is extractable. The real security is enforced server-side in the Edge Function.
 13→// Rotation: bump the endpoint version (cli-telemetry-v3) to rotate the key.
 14→// The Edge Function accepts keys as a Supabase secret (HMAC_KEYS env var), not hardcoded.
 15→const HMAC_KEY = 'REDACTED';
 16→
 17→// Touch file path that tracks whether the one-time disclosure has been shown
 18→const NOTICE_FILE = path.join(getConfigDir(), '.telemetry-notice-shown');
 19→
 20→export interface TelemetryEvent {
 21→  machineId: string;          // SHA-256(hostname:username:monthly-salt)[0:16] — rotates monthly
 22→  command: string;
 23→  subcommand?: string;
 24→  success: boolean;
 25→  cliVersion: string;
 26→  nodeVersion: string;
 27→  os: string;                 // process.platform
 28→  arch: string;               // process.arch
 29→  providers: string[];        // detected from filesystem (which AI tool dirs exist)
 30→  sessionCountBucket: string; // '0' | '1-10' | '11-50' | '51-200' | '200+'
 31→  dataSource: string;         // 'local' | 'none'
 32→  hasHook: boolean;
 33→  timestamp: string;          // YYYY-MM-DD only (day precision — no time, no timezone)
 34→}
 35→
 36→/**
 37→ * Check if telemetry is enabled.
 38→ *
 39→ * Check order (first match wins):
 40→ * 1. CODE_INSIGHTS_TELEMETRY_DISABLED=1 env var — respects CI/automation opt-out
 41→ * 2. DO_NOT_TRACK=1 env var — respects the community standard
 42→ * 3. config.telemetry field — user's explicit preference
 43→ * 4. Default: true (opt-out model)
 44→ */
 45→export function isTelemetryEnabled(): boolean {
 46→  if (process.env.CODE_INSIGHTS_TELEMETRY_DISABLED === '1') return false;
 47→  if (process.env.DO_NOT_TRACK === '1') return false;
 48→
 49→  const config = loadConfig();
 50→  // If explicitly set in config, respect it
 51→  if (config !== null && typeof config.telemetry === 'boolean') {
 52→    return config.telemetry;
 53→  }
 54→
 55→  // Default: enabled (opt-out model)
 56→  return true;
 57→}
 58→
 59→/**
 60→ * Show the one-time telemetry disclosure notice if it hasn't been shown yet.
 61→ *
 62→ * Uses a touch file at ~/.code-insights/.telemetry-notice-shown to track state.
 63→ * Only displays if telemetry is currently enabled — no point disclosing disabled telemetry.
 64→ *
 65→ * Returns true if the notice was shown, false if it was already shown or telemetry is off.
 66→ */
 67→export function showTelemetryNoticeIfNeeded(): boolean {
 68→  if (!isTelemetryEnabled()) return false;
 69→  if (fs.existsSync(NOTICE_FILE)) return false;
 70→
 71→  // Show the disclosure banner
 72→  console.log('');
 73→  console.log('  Code Insights collects anonymous usage data to improve the CLI.');
 74→  console.log('  Includes: command name, OS, CLI version, AI tool types.');
 75→  console.log('  Never includes: file paths, project names, session content, or personal data.');
 76→  console.log('');
 77→  console.log('  Disable: code-insights telemetry disable');
 78→  console.log('  Details: code-insights telemetry status');
 79→  console.log('');
 80→
 81→  // Mark notice as shown — best-effort write, ignore failures
 82→  try {
 83→    // Ensure config dir exists before writing touch file
 84→    const configDir = getConfigDir();
 85→    if (!fs.existsSync(configDir)) {
 86→      fs.mkdirSync(configDir, { recursive: true, mode: 0o700 });
 87→    }
 88→    fs.writeFileSync(NOTICE_FILE, '', { encoding: 'utf-8', mode: 0o600 });
 89→  } catch {
 90→    // Non-fatal — if we can't write the touch file, we'll show the notice again
 91→    // next time. That's acceptable; we don't want to break the CLI over this.
 92→  }
 93→
 94→  return true;
 95→}
 96→
 97→/**
 98→ * Fire-and-forget telemetry event. Does NOT block the calling command.
 99→ *
100→ * Design principles:
101→ * - Never awaited: the caller doesn't wait for this
102→ * - 2s AbortController timeout: we don't hang if the endpoint is slow
103→ * - Swallows ALL errors: network failures, JSON errors, anything — telemetry
104→ *   must never cause a CLI command to fail
105→ * - No retries: if it fails, it fails. Reliability of individual events
106→ *   matters less than not disrupting the user's workflow.
107→ */
108→export function trackEvent(command: string, success: boolean, subcommand?: string): void {
109→  if (!isTelemetryEnabled()) return;
110→
111→  // Build the event synchronously — filesystem reads happen here
112→  let event: TelemetryEvent;
113→  try {
114→    event = buildEvent(command, success, subcommand);
115→  } catch {
116→    // If building the event fails (e.g., filesystem read error), silently skip
117→    return;
118→  }
119→
120→  // Fire-and-forget: intentionally not awaited
121→  // The void cast suppresses the "floating promise" lint warning
122→  void sendEvent(event);
123→}
124→
125→/**
126→ * Build the event payload that would be sent for the given command.
127→ * Exported for use by `telemetry status` to show a preview without sending.
128→ */
129→export function buildEventPreview(command: string): TelemetryEvent {
130→  return buildEvent(command, true);
131→}
132→
133→// ---------------------------------------------------------------------------
134→// Internal helpers
135→// ---------------------------------------------------------------------------
136→
137→/**
138→ * Build a TelemetryEvent with all fields populated.
139→ * Separated from sendEvent so buildEventPreview can reuse it without sending.
140→ */
141→function buildEvent(command: string, success: boolean, subcommand?: string): TelemetryEvent {
142→  return {
143→    machineId: getMachineId(),
144→    command,
145→    subcommand,
146→    success,
147→    cliVersion: getCliVersion(),
148→    nodeVersion: process.version.replace('v', ''),
149→    os: process.platform,
150→    arch: process.arch,
151→    providers: detectProviders(),
152→    sessionCountBucket: getSessionCountBucket(),
153→    dataSource: getDataSource(),
154→    hasHook: detectHook(),
155→    // Day precision only — avoids time-of-day behavioral fingerprinting
156→    timestamp: new Date().toISOString().slice(0, 10),
157→  };
158→}
159→
160→/**
161→ * Anonymous machine ID, rotated monthly.
162→ *
163→ * Format: SHA-256(hostname:username:code-insights-YYYY-MM).slice(0, 16)
164→ *
165→ * Monthly rotation ensures:
166→ * - Long-term tracking is not possible across months
167→ * - Events within a month can be correlated for "unique users" metrics
168→ * - No PII: hostname and username are never sent, only their hash
169→ */
170→function getMachineId(): string {
171→  const now = new Date();
172→  // YYYY-MM format for monthly rotation
173→  const monthSalt = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;
174→
175→  let username: string;
176→  try {
177→    username = os.userInfo().username;
178→  } catch {
179→    // os.userInfo() throws in Docker/CI when UID has no /etc/passwd entry
180→    username = `uid-${process.getuid?.() ?? 'unknown'}`;
181→  }
182→
183→  const input = [os.hostname(), username, `code-insights-${monthSalt}`].join(':');
184→
185→  return crypto.createHash('sha256').update(input).digest('hex').slice(0, 16);
186→}
187→
188→/**
189→ * Read CLI version from package.json.
190→ * Uses createRequire for JSON imports since this is ESM and JSON imports
191→ * have inconsistent support across Node versions and bundlers.
192→ */
193→function getCliVersion(): string {
194→  try {
195→    const require = createRequire(import.meta.url);
196→    // package.json is two levels up from src/utils/ -> src/ -> cli/
197→    const pkg = require('../../package.json') as { version: string };
198→    return pkg.version;
199→  } catch {
200→    return 'unknown';
201→  }
202→}
203→
204→/**
205→ * Detect which AI coding tool data directories exist on this machine.
206→ * We check for the existence of known directories — we never read their contents.
207→ *
208→ * Returns only the tools that are actually present. This tells us which tools
209→ * users are running alongside code-insights, helping us prioritize provider support.
210→ */
211→function detectProviders(): string[] {
212→  const home = os.homedir();
213→  const detected: string[] = [];
214→
215→  // Claude Code: ~/.claude/projects/
216→  if (fs.existsSync(path.join(home, '.claude', 'projects'))) {
217→    detected.push('claude-code');
218→  }
219→
220→  // Cursor: workspace storage directory (cross-platform path)
221→  const cursorStoragePaths = [
222→    // macOS
223→    path.join(home, 'Library', 'Application Support', 'Cursor', 'User', 'workspaceStorage'),
224→    // Linux
225→    path.join(home, '.config', 'Cursor', 'User', 'workspaceStorage'),
226→    // Windows
227→    path.join(home, 'AppData', 'Roaming', 'Cursor', 'User', 'workspaceStorage'),
228→  ];
229→  if (cursorStoragePaths.some((p) => fs.existsSync(p))) {
230→    detected.push('cursor');
231→  }
232→
233→  // Codex CLI: ~/.codex/sessions
234→  if (fs.existsSync(path.join(home, '.codex', 'sessions'))) {
235→    detected.push('codex-cli');
236→  }
237→
238→  // GitHub Copilot CLI: ~/.copilot/session-state
239→  if (fs.existsSync(path.join(home, '.copilot', 'session-state'))) {
240→    detected.push('copilot-cli');
241→  }
242→
243→  return detected;
244→}
245→
246→/**
247→ * Count .jsonl files under ~/.claude/projects/ and bucket the count.
248→ *
249→ * Buckets are intentionally coarse — we want to understand "heavy vs light"
250→ * usage without counting exact files, which could vary wildly and feels more
251→ * private than a range.
252→ */
253→function getSessionCountBucket(): string {
254→  try {
255→    const claudeDir = getClaudeDir();
256→    if (!fs.existsSync(claudeDir)) return '0';
257→
258→    // Count all .jsonl files recursively under the Claude projects directory
259→    let count = 0;
260→    const walk = (dir: string): void => {
261→      const entries = fs.readdirSync(dir, { withFileTypes: true });
262→      for (const entry of entries) {
263→        if (entry.isDirectory()) {
264→          walk(path.join(dir, entry.name));
265→        } else if (entry.name.endsWith('.jsonl')) {
266→          count++;
267→        }
268→      }
269→    };
270→    walk(claudeDir);
271→
272→    // Coarse buckets for privacy — exact session counts are never sent
273→    if (count === 0) return '0';
274→    if (count <= 10) return '1-10';
275→    if (count <= 50) return '11-50';
276→    if (count <= 200) return '51-200';
277→    return '200+';
278→  } catch {
279→    return 'unknown';
280→  }
281→}
282→
283→/**
284→ * Determine the configured data source.
285→ * Always 'local' in Phase 2+ (SQLite-only).
286→ */
287→function getDataSource(): string {
288→  const config = loadConfig();
289→  if (!config) return 'none';
290→  return 'local';
291→}
292→
293→/**
294→ * Check if code-insights is registered as a Claude Code hook.
295→ *
296→ * Reads ~/.claude/settings.json and looks for 'code-insights' anywhere in the
297→ * file content. A hook registration means the user has automated sync on session end.
298→ */
299→function detectHook(): boolean {
300→  try {
301→    const settingsPath = path.join(os.homedir(), '.claude', 'settings.json');
302→    if (!fs.existsSync(settingsPath)) return false;
303→
304→    const content = fs.readFileSync(settingsPath, 'utf-8');
305→    return content.includes('code-insights');
306→  } catch {
307→    return false;
308→  }
309→}
310→
311→/**
312→ * Sign the request body with HMAC-SHA256.
313→ * Returns the hex digest prefixed with 'sha256=' for the X-Signature header.
314→ *
315→ * Note: the key is public (extractable from the npm package) — this is a deterrent
316→ * against casual data poisoning, not a cryptographic secret. Security is enforced
317→ * server-side in the Edge Function using constant-time comparison.
318→ */
319→function signPayload(body: string): string {
320→  const digest = crypto.createHmac('sha256', HMAC_KEY).update(body).digest('hex');
321→  return `sha256=${digest}`;
322→}
323→
324→/**
325→ * Internal: Send the event to the telemetry endpoint.
326→ * AbortController ensures we don't hang longer than 2 seconds.
327→ * All errors are swallowed — telemetry failures must never propagate.
328→ */
329→async function sendEvent(event: TelemetryEvent): Promise<void> {
330→  const controller = new AbortController();
331→  // 2s timeout — enough for a healthy network, short enough to not delay anything
332→  const timer = setTimeout(() => controller.abort(), 2000);
333→
334→  try {
335→    const body = JSON.stringify(event);
336→    await fetch(TELEMETRY_ENDPOINT, {
337→      method: 'POST',
338→      headers: {
339→        'Content-Type': 'application/json',
340→        // HMAC signature — lets the Edge Function verify the payload wasn't tampered.
341→        // The v2 endpoint accepts but does not require this header initially, allowing
342→        // older CLI versions (which don't send it) to continue working.
343→        'X-Signature': signPayload(body),
344→      },
345→      body,
346→      signal: controller.signal,
347→    });
348→  } catch {
349→    // Swallow everything: network errors, AbortError, JSON serialization errors.
350→    // Telemetry failures are silent — the CLI command already completed.
351→  } finally {
352→    clearTimeout(timer);
353→  }
354→}
