 49→// GET /api/analysis/session/stream?sessionId=X
 50→// SSE endpoint — streams progress events during session analysis.
 51→// onProgress is non-async because analyzeSession calls it without await;
 52→// stream.writeSSE is fire-and-forget for progress events (non-fatal if missed).
 53→app.get('/session/stream', async (c) => {
 54→  if (!isLLMConfigured()) {
 55→    return c.json({
 56→      success: false,
 57→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 58→    }, 400);
 59→  }
 60→
 61→  const sessionId = c.req.query('sessionId');
 62→  if (!sessionId) {
 63→    return c.json({ error: 'Missing required query param: sessionId' }, 400);
 64→  }
 65→
 66→  const db = getDb();
 67→
 68→  const session = db.prepare(`
 69→    SELECT id, project_id, project_name, project_path, summary, ended_at
 70→    FROM sessions WHERE id = ?
 71→  `).get(sessionId) as SessionData | undefined;
 72→
 73→  if (!session) {
 74→    return c.json({ error: 'Session not found' }, 404);
 75→  }
 76→
 77→  const messages = db.prepare(`
 78→    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
 79→    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
 80→  `).all(sessionId) as SQLiteMessageRow[];
 81→
 82→  return streamSSE(c, async (stream) => {
 83→    try {
 84→      const abortSignal = c.req.raw.signal;
 85→
 86→      await stream.writeSSE({
 87→        event: 'progress',
 88→        data: JSON.stringify({ phase: 'loading_messages', message: 'Loading messages...' }),
 89→      });
 90→
 91→      const result = await analyzeSession(session, messages, {
 92→        signal: abortSignal,
 93→        onProgress: (progress) => {
 94→          const message = progress.phase === 'saving'
 95→            ? 'Saving insights...'
 96→            : progress.currentChunk && progress.totalChunks
 97→              ? `Analyzing... (${progress.currentChunk} of ${progress.totalChunks})`
 98→              : 'Analyzing...';
 99→          void stream.writeSSE({
100→            event: 'progress',
101→            data: JSON.stringify({ ...progress, message }),
102→          }).catch(() => {});
103→        },
104→      });
105→
106→      if (result.success) {
107→        trackEvent('analysis', true, 'session');
108→        const summaryInsight = result.insights.find(i => i.type === 'summary');
109→        await stream.writeSSE({
110→          event: 'complete',
111→          data: JSON.stringify({
112→            success: true,
113→            insightCount: result.insights.length,
114→            tokenUsage: result.usage,
115→            suggestedTitle: summaryInsight?.title ?? null,
116→          }),
117→        });
118→      } else {
119→        await stream.writeSSE({
120→          event: 'error',
121→          data: JSON.stringify({ error: result.error ?? 'Analysis failed' }),
122→        });
123→      }
124→    } catch (err) {
125→      const message = err instanceof Error ? err.message : 'Unknown error';
126→      await stream.writeSSE({
127→        event: 'error',
128→        data: JSON.stringify({ error: message }),
129→      }).catch(() => {});
130→    }
131→  });
132→});
