255→// Finds recurring insight patterns across sessions.
256→app.post('/recurring', async (c) => {
257→  if (!isLLMConfigured()) {
258→    return c.json({
259→      success: false,
260→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
261→    }, 400);
262→  }
263→
264→  const body = await c.req.json<{ projectId?: string; limit?: number }>();
265→  const db = getDb();
266→
267→  const conditions: string[] = [];
268→  const params: (string | number)[] = [];
269→
270→  if (body.projectId) {
271→    conditions.push('project_id = ?');
272→    params.push(body.projectId);
273→  }
274→
275→  const where = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';
276→  const limit = Math.min(parseIntParam(String(body.limit ?? ''), 200), 200);
277→
278→  const insights = db.prepare(`
279→    SELECT id, type, title, summary, project_name, session_id
280→    FROM insights
281→    ${where}
282→    ORDER BY timestamp DESC
283→    LIMIT ?
284→  `).all(...params, limit) as Array<{
285→    id: string;
286→    type: string;
287→    title: string;
288→    summary: string;
289→    project_name: string;
290→    session_id: string;
291→  }>;
292→
293→  const result = await findRecurringInsights(insights);
294→  if (result.success) trackEvent('analysis', true, 'recurring');
295→  return c.json(result, result.success ? 200 : 422);
