  1→import { Command } from 'commander';
  2→import chalk from 'chalk';
  3→import { loadConfig, saveConfig } from '../utils/config.js';
  4→import { isTelemetryEnabled, buildEventPreview } from '../utils/telemetry.js';
  5→import type { ClaudeInsightConfig } from '../types.js';
  6→
  7→/**
  8→ * Minimal config shape used when no config file exists yet but the user
  9→ * explicitly opts in/out of telemetry before running `init`.
 10→ */
 11→const MINIMAL_CONFIG: ClaudeInsightConfig = {
 12→  sync: { claudeDir: '~/.claude/projects', excludeProjects: [] },
 13→};
 14→
 15→/**
 16→ * Show telemetry status and a full field-level explanation of what is collected.
 17→ * Also renders a live event preview when telemetry is enabled so users can see
 18→ * exactly what would be sent — no guessing required.
 19→ */
 20→function statusAction(): void {
 21→  const enabled = isTelemetryEnabled();
 22→
 23→  console.log(chalk.cyan('\n  Telemetry\n'));
 24→  console.log(chalk.white(`  Status: ${enabled ? chalk.green('ENABLED') : chalk.yellow('DISABLED')}`));
 25→
 26→  // Surface environment-variable overrides so users know why the config value
 27→  // might appear to have no effect.
 28→  if (process.env.CODE_INSIGHTS_TELEMETRY_DISABLED === '1') {
 29→    console.log(chalk.gray('  (Disabled via CODE_INSIGHTS_TELEMETRY_DISABLED env var)'));
 30→  }
 31→  if (process.env.DO_NOT_TRACK === '1') {
 32→    console.log(chalk.gray('  (Disabled via DO_NOT_TRACK env var)'));
 33→  }
 34→
 35→  console.log(chalk.white('\n  What we collect (and nothing else):'));
 36→
 37→  const preview = buildEventPreview('telemetry');
 38→  const fields: [string, string][] = [
 39→    ['command', 'The command you ran (e.g., "sync", "stats")'],
 40→    ['subcommand', 'Subcommand if any (e.g., "cost", "today")'],
 41→    ['success', 'Whether it succeeded'],
 42→    ['cliVersion', preview.cliVersion],
 43→    ['nodeVersion', preview.nodeVersion],
 44→    ['os', `${preview.os} (${preview.arch})`],
 45→    ['providers', `[${preview.providers.join(', ')}]`],
 46→    ['sessionBucket', preview.sessionCountBucket],
 47→    ['dataSource', preview.dataSource],
 48→    ['hasHook', String(preview.hasHook)],
 49→  ];
 50→
 51→  for (const [key, value] of fields) {
 52→    console.log(chalk.gray(`    ${key.padEnd(16)} ${value}`));
 53→  }
 54→
 55→  console.log(chalk.white('\n  What we NEVER collect:'));
 56→  console.log(chalk.gray('    File paths, project names, session content, API keys,'));
 57→  console.log(chalk.gray('    git URLs, hostnames, or anything personally identifiable.'));
 58→
 59→  // Only show the live event preview when telemetry is on — if it's off there
 60→  // is nothing to preview and showing it could be confusing.
 61→  if (enabled) {
 62→    console.log(chalk.white('\n  Event preview (what would be sent now):'));
 63→    console.log(chalk.gray(`    ${JSON.stringify(preview, null, 2).split('\n').join('\n    ')}`));
 64→  }
 65→
 66→  console.log(chalk.white('\n  To change:'));
 67→  console.log(chalk.gray('    code-insights telemetry disable'));
 68→  console.log(chalk.gray('    code-insights telemetry enable'));
 69→  console.log(chalk.gray('    Or set env: CODE_INSIGHTS_TELEMETRY_DISABLED=1\n'));
 70→}
 71→
 72→/**
 73→ * Persist telemetry = false to config.
 74→ * If no config file exists yet we write a minimal one — the user clearly has
 75→ * an intent to opt out and we should honour it without forcing them to run init
 76→ * first.
 77→ */
 78→function disableAction(): void {
 79→  const config = loadConfig() ?? { ...MINIMAL_CONFIG };
 80→  config.telemetry = false;
 81→  saveConfig(config);
 82→  console.log(chalk.green('\n  Telemetry disabled.\n'));
 83→}
 84→
 85→/**
 86→ * Persist telemetry = true to config.
 87→ * Same minimal-config fallback as disableAction.
 88→ */
 89→function enableAction(): void {
 90→  const config = loadConfig() ?? { ...MINIMAL_CONFIG };
 91→  config.telemetry = true;
 92→  saveConfig(config);
 93→  console.log(chalk.green('\n  Telemetry enabled.\n'));
 94→}
