 10→import { setProviderVerbose } from '../providers/context.js';
 11→import type { SessionProvider } from '../providers/types.js';
 12→import type { SyncState } from '../types.js';
 13→import { splitVirtualPath } from '../utils/paths.js';
 14→
 15→interface SyncOptions {
 16→  force?: boolean;
 17→  project?: string;
 18→  dryRun?: boolean;
 19→  quiet?: boolean;
 20→  verbose?: boolean;
 21→  regenerateTitles?: boolean;
 22→  source?: string;
 23→}
 24→
 25→export interface SyncResult {
 26→  syncedCount: number;
 27→  messageCount: number;
 28→  errorCount: number;
 29→  updatedExistingCount: number;
 30→}
 31→
 32→/**
 33→ * Core sync logic — reusable from stats commands and other callers.
 34→ *
 35→ * Parses sessions from all configured providers and writes to local SQLite.
 36→ * Throws on fatal errors (unknown provider) instead of calling process.exit().
 37→ * Returns a SyncResult summary.
 38→ */
 39→export async function runSync(options: SyncOptions = {}): Promise<SyncResult> {
 40→  const log = options.quiet ? () => {} : console.log.bind(console);
 41→  const noopSpinner = {
 42→    start: function() { return this; },
 43→    succeed: function() { return this; },
 44→    fail: function() { return this; },
 45→    warn: function() { return this; },
 46→    info: function() { return this; },
 47→    stop: function() { return this; },
 48→  };
 49→  const createSpinner = options.quiet
 50→    ? () => noopSpinner
 51→    : ora;
 52→
 53→  log(chalk.cyan('\n  Code Insights Sync\n'));
 54→
 55→  // Initialize database (runs migrations if needed)
 56→  const spinner = createSpinner('Initializing database...').start();
 57→  try {
 58→    getDb();
 59→    spinner.succeed('Database ready');
 60→  } catch (error) {
 61→    spinner.fail('Failed to initialize database');
 62→    throw new Error(`Database error: ${error instanceof Error ? error.message : 'Unknown error'}`);
 63→  }
 64→
 65→  // Dry-run banner
 66→  if (options.dryRun) {
 67→    log(chalk.yellow('\n  Dry run -- no changes will be made'));
 68→  }
 69→
 70→  // Set verbose flag for providers (e.g., gates Cursor diagnostic warnings)
 71→  setProviderVerbose(!!options.verbose);
 72→
 73→  // Get providers to sync
 74→  let providers: SessionProvider[];
 75→  if (options.source) {
 76→    try {
 77→      providers = [getProvider(options.source)];
 78→    } catch {
 79→      throw new Error(`Unknown source: ${options.source}. Available: ${getAllProviders().map(p => p.getProviderName()).join(', ')}`);
 80→    }
 81→  } else {
 82→    providers = getAllProviders();
 83→  }
 84→
 85→  // Load sync state
 86→  // When --force is used with --source, only clear the targeted provider's entries
 87→  // instead of nuking the entire sync state.
 88→  const syncState = loadSyncState();
 89→  if (options.force) {
 90→    if (options.source) {
 91→      // Targeted force: remove only entries belonging to the specified provider's files
 92→      const targetProviderPaths = new Set<string>();
 93→      for (const provider of providers) {
 94→        const discovered = await provider.discover({ projectFilter: options.project });
 95→        for (const p of discovered) {
 96→          const { realPath } = splitVirtualPath(p);
 97→          targetProviderPaths.add(realPath);
 98→        }
 99→      }
100→      for (const key of Object.keys(syncState.files)) {
101→        if (targetProviderPaths.has(key)) {
102→          delete syncState.files[key];
103→        }
104→      }
105→    } else {
106→      // Full force: reset everything
107→      syncState.files = {};
108→    }
109→  }
110→
111→  let totalSyncedCount = 0;
112→  let totalMessageCount = 0;
113→  let totalErrorCount = 0;
114→  let totalUpdatedExisting = 0;
115→
116→  for (const provider of providers) {
117→    const providerName = provider.getProviderName();
118→    try {
119→      if (providers.length > 1) {
120→        log(chalk.cyan(`\n  Syncing ${providerName}...`));
121→      }
122→
123→      // Discovery
124→      spinner.start(`Discovering ${providerName} sessions...`);
125→      const sessionFiles = await provider.discover({ projectFilter: options.project });
126→      spinner.succeed(`Found ${sessionFiles.length} ${providerName} session files`);
127→
128→      if (sessionFiles.length === 0) continue;
129→
130→      // Filter to only new/modified files
131→      const filesToSync = filterFilesToSync(sessionFiles, syncState, options.force);
132→      log(chalk.gray(`  ${filesToSync.length} files need syncing (${sessionFiles.length - filesToSync.length} already synced)`));
133→
134→      if (filesToSync.length === 0) continue;
135→
136→      if (options.dryRun) {
137→        for (const file of filesToSync) {
138→          log(chalk.gray(`  Would sync: ${path.basename(file)}`));
139→        }
140→        continue;
141→      }
142→
143→      // Process files — accumulate per-provider counts, show one summary line after
144→      let providerSyncedCount = 0;
145→      let providerUpdatedCount = 0;
146→      let providerSkippedCount = 0;
147→      let providerMessageCount = 0;
148→
149→      for (const filePath of filesToSync) {
150→        const fileName = path.basename(filePath);
151→        spinner.start(`Processing ${fileName}...`);
152→
153→        try {
154→          // Parse session
155→          const session = await provider.parse(filePath);
156→          if (!session) {
157→            providerSkippedCount++;
158→            continue;
159→          }
160→
161→          // Write session and messages to SQLite
162→          const isNew = insertSessionWithProjectAndReturnIsNew(session, !!options.force);
163→          insertMessages(session);
164→
165→          // Update and persist sync state after each file
166→          // so progress survives crashes
167→          updateSyncState(syncState, filePath, session.id);
168→          saveSyncState(syncState);
169→
170→          if (!isNew && !options.force) {
171→            providerUpdatedCount++;
172→            totalUpdatedExisting++;
173→          }
174→
175→          providerSyncedCount++;
176→          providerMessageCount += session.messages.length;
177→          totalSyncedCount++;
178→          totalMessageCount += session.messages.length;
179→        } catch (error) {
180→          totalErrorCount++;
181→          spinner.fail(`Failed to sync ${fileName}`);
182→          if (!options.quiet) {
183→            console.error(chalk.red(`  ${error instanceof Error ? error.message : 'Unknown error'}`));
184→          }
185→        }
186→      }
187→
188→      // One summary line per provider instead of per-file noise
189→      spinner.stop();
190→      if (providerSyncedCount > 0 || providerSkippedCount > 0) {
191→        const providerNewCount = providerSyncedCount - providerUpdatedCount;
192→        const parts: string[] = [];
193→        if (providerNewCount > 0) parts.push(`${providerNewCount} new`);
194→        if (providerUpdatedCount > 0) parts.push(`${providerUpdatedCount} updated`);
195→        if (parts.length === 0) parts.push('0 synced');
196→        const syncedPart = `${parts.join(', ')}${providerMessageCount > 0 ? ` (${providerMessageCount.toLocaleString()} messages)` : ''}`;
197→        const skippedPart = providerSkippedCount > 0
198→          ? `, ${providerSkippedCount} empty`
199→          : '';
200→        log(chalk.gray(`  ${syncedPart}${skippedPart}`));
201→      }
202→    } catch (error) {
203→      totalErrorCount++;
204→      spinner.fail(`Failed to sync ${providerName}`);
205→      if (!options.quiet) {
206→        console.error(chalk.red(`  ${error instanceof Error ? error.message : 'Unknown error'}`));
207→      }
208→    }
209→  }
210→
211→  // Reconcile usage stats after force sync (skip if nothing changed)
212→  const shouldRecalculateUsageStats = options.force
213→    ? (totalSyncedCount > 0 || totalErrorCount > 0)
214→    : totalUpdatedExisting > 0;
215→
216→  if (shouldRecalculateUsageStats) {
217→    spinner.start('Recalculating usage stats...');
218→    try {
219→      const result = recalculateUsageStats();
220→      spinner.succeed(`Usage stats reconciled (${result.sessionsWithUsage} sessions with usage data)`);
221→    } catch (error) {
222→      spinner.warn('Could not reconcile usage stats');
223→      if (!options.quiet) {
224→        console.error(chalk.red(`  ${error instanceof Error ? error.message : 'Unknown error'}`));
225→      }
226→    }
227→  }
228→
229→  // Save sync state
230→  syncState.lastSync = new Date().toISOString();
231→  saveSyncState(syncState);
232→
233→  return {
234→    syncedCount: totalSyncedCount,
235→    messageCount: totalMessageCount,
236→    errorCount: totalErrorCount,
237→    updatedExistingCount: totalUpdatedExisting,
238→  };
239→}
240→
241→/**
242→ * Sync AI coding sessions to local SQLite database
243→ */
244→export async function syncCommand(options: SyncOptions = {}): Promise<void> {
245→  const log = options.quiet ? () => {} : console.log.bind(console);
246→
247→  try {
248→    const result = await runSync(options);
249→
250→    // Summary (only if not quiet)
251→    if (result.syncedCount === 0 && result.errorCount === 0) {
252→      log(chalk.green('\n  Already up to date!'));
253→      trackEvent('sync', true);
254→      return;
255→    }
256→    log(chalk.cyan('\n  Sync Summary'));
257→    const newCount = Math.max(result.syncedCount - result.updatedExistingCount, 0);
258→    log(chalk.white(`  Sessions new: ${newCount}`));
259→    if (result.updatedExistingCount > 0) {
260→      log(chalk.white(`  Sessions updated: ${result.updatedExistingCount}`));
261→    }
262→    log(chalk.white(`  Messages synced: ${result.messageCount}`));
263→    if (result.errorCount > 0) {
264→      log(chalk.red(`  Errors: ${result.errorCount}`));
265→    }
266→    log(chalk.green('\n  Sync complete!'));
267→    trackEvent('sync', true);
268→  } catch (error) {
269→    trackEvent('sync', false);
270→    if (!options.quiet) {
271→      console.error(chalk.red(error instanceof Error ? error.message : 'Sync failed'));
272→    }
273→    process.exit(1);
274→  }
275→}
276→
277→/**
278→ * Filter files to only those that need syncing
279→ */
280→function filterFilesToSync(files: string[], syncState: SyncState, force?: boolean): string[] {
281→  if (force) return files;
282→
283→  return files.filter((filePath) => {
284→    const { realPath, sessionFragment } = splitVirtualPath(filePath);
285→    const stat = fs.statSync(realPath);
286→    const lastModified = stat.mtime.toISOString();
287→    const fileState = syncState.files[realPath];
288→
289→    // If file was never synced, sync it
290→    if (!fileState) return true;
291→
292→    if (sessionFragment) {
293→      // Virtual path (multi-session DB).
294→      // If the DB file changed, re-sync all sessions from it.
295→      if (fileState.lastModified !== lastModified) return true;
296→
297→      // Otherwise only sync sessions we haven't seen yet.
298→      if (fileState.syncedSessionIds) {
299→        return !fileState.syncedSessionIds.includes(sessionFragment);
300→      }
301→
302→      // Virtual path but no syncedSessionIds tracked yet — needs sync
303→      return true;
304→    }
305→
306→    // For regular files, check if modified since last sync
307→    return fileState.lastModified !== lastModified;
308→  });
309→}
310→
311→/**
312→ * Update sync state for a file
313→ */
314→function updateSyncState(state: SyncState, filePath: string, sessionId: string): void {
315→  const { realPath, sessionFragment } = splitVirtualPath(filePath);
316→  const stat = fs.statSync(realPath);
317→
318→  if (sessionFragment) {
319→    // Virtual path: track the session fragment in syncedSessionIds
320→    const existing = state.files[realPath];
321→    const syncedIds = existing?.syncedSessionIds || [];
322→    if (!syncedIds.includes(sessionFragment)) {
323→      syncedIds.push(sessionFragment);
324→    }
325→    state.files[realPath] = {
326→      lastModified: stat.mtime.toISOString(),
327→      lastSyncedLine: 0,
328→      sessionId,
329→      syncedSessionIds: syncedIds,
330→    };
331→  } else {
332→    // Regular file path
333→    state.files[realPath] = {
334→      lastModified: stat.mtime.toISOString(),
335→      lastSyncedLine: 0,
336→      sessionId,
337→    };
338→  }
339→}
