  1→import { serve } from '@hono/node-server';
  2→import { serveStatic } from '@hono/node-server/serve-static';
  3→import { Hono } from 'hono';
  4→import { existsSync, readFileSync } from 'fs';
  5→import { relative, join } from 'path';
  6→import { openUrl } from '@code-insights/cli/utils/browser';
  7→import projectsRouter from './routes/projects.js';
  8→import sessionsRouter from './routes/sessions.js';
  9→import messagesRouter from './routes/messages.js';
 10→import insightsRouter from './routes/insights.js';
 11→import analysisRouter from './routes/analysis.js';
 12→import analyticsRouter from './routes/analytics.js';
 13→import configRouter from './routes/config.js';
 14→import exportRouter from './routes/export.js';
 15→
 16→export interface ServerOptions {
 17→  port: number;
 18→  // Absolute path to the dashboard/dist directory
 19→  staticDir: string;
 20→  openBrowser: boolean;
 21→}
 22→
 23→/**
 24→ * Create the Hono app with all API routes mounted.
 25→ * Does NOT add static file serving or call serve() — that's startServer's job.
 26→ * Exported so tests can use app.request() without starting a real server.
 27→ */
 28→export function createApp(): Hono {
 29→  const app = new Hono();
 30→
 31→  // Global error handler — prevents stack trace leakage to clients.
 32→  // Detects malformed JSON bodies (SyntaxError) and returns 400 instead of 500.
 33→  app.onError((err, c) => {
 34→    if (err instanceof SyntaxError && err.message.includes('JSON')) {
 35→      return c.json({ error: 'Invalid JSON in request body' }, 400);
 36→    }
 37→    console.error(err);
 38→    return c.json({ error: 'Internal server error' }, 500);
 39→  });
 40→
 41→  // API routes — all under /api
 42→  app.route('/api/projects', projectsRouter);
 43→  app.route('/api/sessions', sessionsRouter);
 44→  app.route('/api/messages', messagesRouter);
 45→  app.route('/api/insights', insightsRouter);
 46→  app.route('/api/analysis', analysisRouter);
 47→  app.route('/api/analytics', analyticsRouter);
 48→  app.route('/api/config', configRouter);
 49→  app.route('/api/export', exportRouter);
 50→
 51→  // Health check
 52→  app.get('/api/health', (c) => c.json({ ok: true, version: '0.1.0' }));
 53→
 54→  // API 404 catch-all — must come AFTER all /api sub-routers and BEFORE static serving.
 55→  // Without this, unmatched /api/* routes fall through to the SPA fallback and return
 56→  // index.html as 200, which breaks API clients expecting JSON errors.
 57→  app.all('/api/*', (c) => c.json({ error: 'Not found' }, 404));
 58→
 59→  return app;
 60→}
 61→
 62→/**
 63→ * Start the Code Insights local dashboard server.
 64→ * Calls createApp(), adds static file serving + SPA fallback if staticDir exists,
 65→ * then calls serve().
 66→ * Called by the CLI `dashboard` command.
 67→ */
 68→export async function startServer(options: ServerOptions): Promise<void> {
 69→  const { port, staticDir, openBrowser } = options;
 70→
 71→  const app = createApp();
 72→
 73→  // Static file serving — only if the dashboard has been built.
 74→  // serveStatic requires a path relative to process.cwd(), not an absolute path.
 75→  if (existsSync(staticDir)) {
 76→    const relativeStaticDir = relative(process.cwd(), staticDir);
 77→    app.use('/*', serveStatic({ root: relativeStaticDir }));
 78→
 79→    // Cache index.html at startup — avoids a readFileSync on every SPA navigation
 80→    // request, which would be a pointless disk read for a file that never changes
 81→    // while the server is running.
 82→    const indexPath = join(staticDir, 'index.html');
 83→    const indexHtml = existsSync(indexPath) ? readFileSync(indexPath, 'utf-8') : null;
 84→
 85→    // SPA fallback: any non-API route not matched by serveStatic serves index.html
 86→    // so react-router can handle client-side routing.
 87→    app.get('*', (c) => {
 88→      if (indexHtml) return c.html(indexHtml);
 89→      return c.text('Dashboard not found. Run pnpm build first.', 404);
 90→    });
 91→  } else {
 92→    // Dashboard not built — serve a helpful message
 93→    app.get('*', (c) =>
 94→      c.html(`
 95→        <html><body style="font-family:monospace;padding:2rem">
 96→          <h2>Code Insights Dashboard</h2>
 97→          <p>The dashboard has not been built yet.</p>
 98→          <pre>pnpm install &amp;&amp; pnpm build</pre>
 99→          <p>Then restart the server.</p>
100→        </body></html>
101→      `),
102→    );
103→  }
104→
105→  // Graceful shutdown: just call process.exit(0).
106→  // The process 'exit' handler in cli/src/db/client.ts already calls closeDb()
107→  // which runs WAL checkpoint. Calling closeDb() here would double-close.
108→  const shutdown = () => {
109→    process.exit(0);
110→  };
111→  process.on('SIGINT', shutdown);
112→  process.on('SIGTERM', shutdown);
113→
114→  serve({ fetch: app.fetch, port }, (info) => {
115→    const url = `http://localhost:${info.port}`;
116→    console.log(`  Code Insights dashboard running at ${url}`);
117→    if (openBrowser) {
118→      openUrl(url);
119→    }
120→  });
121→}
